#include<bits/stdc++.h>
const int MAXN=26*25+26;
int MAP[MAXN][MAXN],N,ANS=0,INT_city,INT_province;
std::string city,province;
int main(void){
	std::ios::sync_with_stdio(false);
	std::cin>>N;
	for(int i=0;i<N;i++){
		std::cin>>city>>province;
		INT_city=int(city[0]-'A')*26+int(city[1]-'A');
		INT_province=int(province[0]-'A')*26+int(province[1]-'A');
		if(INT_province!=INT_city){
			MAP[INT_city][INT_province]++;
            ANS+=MAP[INT_province][INT_city];
		}
	}
	std::cout<<ANS;
    return false;
}
